import { existsSync, mkdirSync, readFileSync, renameSync, writeFileSync, } from "node:fs";
import { dirname } from "node:path";
import { providerNames } from "../types.js";
function isRecord(value) {
    return typeof value === "object" && value !== null && !Array.isArray(value);
}
function normalizeProvider(value, fallback) {
    if (typeof value === "string" && providerNames.includes(value)) {
        return value;
    }
    return fallback;
}
function normalizeOverrides(input) {
    if (!isRecord(input)) {
        return {};
    }
    const output = {};
    for (const provider of providerNames) {
        const value = input[provider];
        if (typeof value === "string" && value.trim()) {
            output[provider] = value.trim();
        }
    }
    return output;
}
function normalizeHistory(input) {
    if (!Array.isArray(input)) {
        return [];
    }
    const history = [];
    for (const item of input) {
        if (!isRecord(item)) {
            continue;
        }
        const role = item.role;
        const content = item.content;
        if ((role === "user" || role === "assistant") &&
            typeof content === "string" &&
            content.length > 0) {
            history.push({ role, content });
        }
    }
    return history;
}
export class SessionStore {
    defaultProvider;
    maxHistory;
    sessions = new Map();
    persistencePath;
    constructor(defaultProvider, maxHistory, persistencePath) {
        this.defaultProvider = defaultProvider;
        this.maxHistory = maxHistory;
        this.persistencePath = persistencePath?.trim() || undefined;
        this.loadFromDisk();
    }
    getSessionCount() {
        return this.sessions.size;
    }
    getPersistencePath() {
        return this.persistencePath;
    }
    getProvider(chatKey) {
        return this.getOrCreate(chatKey).provider;
    }
    setProvider(chatKey, provider) {
        const session = this.getOrCreate(chatKey);
        session.provider = provider;
        this.persist();
    }
    reset(chatKey) {
        this.sessions.delete(chatKey);
        this.persist();
    }
    getModel(chatKey, provider) {
        return this.getOrCreate(chatKey).modelOverrides[provider];
    }
    setModel(chatKey, provider, model) {
        const session = this.getOrCreate(chatKey);
        if (!model?.trim()) {
            delete session.modelOverrides[provider];
            this.persist();
            return;
        }
        session.modelOverrides[provider] = model.trim();
        this.persist();
    }
    getReasoningEffort(chatKey, provider) {
        return this.getOrCreate(chatKey).reasoningEffortOverrides[provider];
    }
    setReasoningEffort(chatKey, provider, effort) {
        const session = this.getOrCreate(chatKey);
        if (!effort?.trim()) {
            delete session.reasoningEffortOverrides[provider];
            this.persist();
            return;
        }
        session.reasoningEffortOverrides[provider] = effort.trim();
        this.persist();
    }
    buildPrompt(chatKey, userText, systemPrompt) {
        const session = this.getOrCreate(chatKey);
        const messages = systemPrompt
            ? [{ role: "system", content: systemPrompt }]
            : [];
        messages.push(...session.history);
        messages.push({ role: "user", content: userText });
        return messages;
    }
    appendExchange(chatKey, userText, assistantText) {
        const session = this.getOrCreate(chatKey);
        session.history.push({ role: "user", content: userText });
        session.history.push({ role: "assistant", content: assistantText });
        if (session.history.length > this.maxHistory) {
            let trimmed = session.history.slice(-this.maxHistory);
            if (trimmed[0]?.role === "assistant") {
                trimmed = trimmed.slice(1);
            }
            session.history = trimmed;
        }
        this.persist();
    }
    getOrCreate(chatKey) {
        const existing = this.sessions.get(chatKey);
        if (existing) {
            return existing;
        }
        const session = {
            provider: this.defaultProvider,
            history: [],
            modelOverrides: {},
            reasoningEffortOverrides: {},
        };
        this.sessions.set(chatKey, session);
        return session;
    }
    loadFromDisk() {
        if (!this.persistencePath || !existsSync(this.persistencePath)) {
            return;
        }
        try {
            const raw = JSON.parse(readFileSync(this.persistencePath, "utf8"));
            if (!isRecord(raw) || raw.version !== 1 || !isRecord(raw.sessions)) {
                console.warn(`[openshell] session store format is invalid: ${this.persistencePath}`);
                return;
            }
            for (const [chatKey, value] of Object.entries(raw.sessions)) {
                if (!isRecord(value)) {
                    continue;
                }
                const session = {
                    provider: normalizeProvider(value.provider, this.defaultProvider),
                    history: this.trimHistory(normalizeHistory(value.history)),
                    modelOverrides: normalizeOverrides(value.modelOverrides),
                    reasoningEffortOverrides: normalizeOverrides(value.reasoningEffortOverrides),
                };
                this.sessions.set(chatKey, session);
            }
        }
        catch (error) {
            console.warn(`[openshell] failed to load session store: ${this.persistencePath}`, error);
        }
    }
    persist() {
        if (!this.persistencePath) {
            return;
        }
        try {
            const payload = {
                version: 1,
                savedAt: new Date().toISOString(),
                sessions: Object.fromEntries(this.sessions),
            };
            const dir = dirname(this.persistencePath);
            mkdirSync(dir, { recursive: true });
            const tempPath = `${this.persistencePath}.tmp`;
            writeFileSync(tempPath, JSON.stringify(payload, null, 2), "utf8");
            renameSync(tempPath, this.persistencePath);
        }
        catch (error) {
            console.warn(`[openshell] failed to persist session store: ${this.persistencePath}`, error);
        }
    }
    trimHistory(history) {
        if (history.length <= this.maxHistory) {
            return history;
        }
        let trimmed = history.slice(-this.maxHistory);
        if (trimmed[0]?.role === "assistant") {
            trimmed = trimmed.slice(1);
        }
        return trimmed;
    }
}
